# Семинар: Линейная регрессия (векторизованная версия)


**Цели:**
- закрепить `NumPy`, `Pandas`, `Matplotlib`;
- реализовать линрег в векторной форме;
- использовать сразу две метрики: `MSE` и `MAE`;
- понять переобучение и роль регуляризации (`Ridge`, `Lasso`).

**Важно по реализации:**
- все функции работают с векторами/матрицами `NumPy`;
- параметр смещения `b` включен в вектор весов `w` (через добавление bias-столбца единиц).

def add_bias(X):
    X = np.asarray(X)
    if X.ndim == 1:
        X = X.reshape(-1, 1)
    return np.hstack([np.ones((X.shape[0], 1)), X])

def predict(Xb, w):
    return Xb @ w

def mse(y_true, y_pred):
    return np.mean((y_pred - y_true)**2)

def mae(y_true, y_pred):
    return np.mean(abs(y_pred - y_true))

def grad_mse(Xb, y_true, w):
    n = Xb.shape[0]
    err = Xb @ w - y_true
    return (2.0 / n) * (Xb.T @ err)

def fit_gd_mse(Xb, y_true, lr=0.01, n_steps=1000):
    w = np.zeros(Xb.shape[1])
    history = {'mse': [], 'mae': []}
    for _ in range(n_steps):
        w -= lr * grad_mse(Xb, y_true, w)
        y_pred = Xb @ w
        history['mse'].append(mse(y_true, y_pred))
        history['mae'].append(mae(y_true, y_pred))
    return w, history

def poly_features(x, degree):
    """Получим матрицу: [1, x, x^2, ..., x^degree]."""
    x = np.asarray(x)
    return np.column_stack([x**k for k in range(degree + 1)])

def predict_from_X(X, w):
    return X @ w

def predict_poly(x, w):
    degree = len(w) - 1
    return poly_features(x, degree) @ w

def mse(y_true, y_pred):
    return np.mean((y_pred - y_true)**2)

def grad_mse(X, y, w):
    n = X.shape[0]
    return (2/n) * (X.T @ (X @ w - y))

def grad_ridge(X, y, w, lam=0.0, regularize_bias=False):
    g = grad_mse(X, y, w)
    if lam > 0:
        reg = 2 * lam * w
        if not regularize_bias:
            reg[0] = 0.0
        g = g + reg
    return g

def fit_poly_gd(x, y, degree, lr=0.01, n_steps=30000, lam=0.0, regularize_bias=False):
    X = poly_features(x, degree)
    w = np.zeros(X.shape[1])
    history = np.empty(n_steps)

    for t in range(n_steps):
        y_pred = X @ w
        history[t] = mse(y, y_pred)
        w -= lr * grad_ridge(X, y, w, lam=lam, regularize_bias=regularize_bias)

    return w, history
